class Solution {
public:
    vector<vector<int>> validArrangement(vector<vector<int>>& pairs) {
        unordered_map<int, vector<int>> adj;
        unordered_map<int, int> deg;
        for (auto& p : pairs) {
            int u = p[0], v = p[1];
            adj[u].push_back(v);
            deg[u]++;
            deg[v]--;
        }
        int start = pairs[0][0];
        for (auto& [node, d] : deg) {
            if (d == 1) {
                start = node;
                break;
            }
        }
        vector<vector<int>> res;
        stack<int> st;
        st.push(start);
        while (!st.empty()) {
            int u = st.top();
            if (!adj[u].empty()) {
                int v = adj[u].back();
                adj[u].pop_back();
                st.push(v);
            } else {
                if (st.size() > 1) {
                    int v = st.top(); st.pop();
                    int u = st.top();
                    res.push_back({u, v});
                } else {
                    st.pop();
                }
            }
        }
        reverse(res.begin(), res.end());
        return res;
    }
};
```
